USER_EDITABLE_FIELDS = {'email', 'username'}

# Privileged fields that only admins can modify
ADMIN_ONLY_FIELDS = {'account_type', 'credits', 'referral_code', 'verified_status'}

ALL_VALID_FIELDS = USER_EDITABLE_FIELDS | ADMIN_ONLY_FIELDS


def is_admin(user):
    """Check if user has admin role."""
    return getattr(user, 'role', None) == 'admin'


@app.route('/api/profile', methods=['PATCH'])
@login_required
def update_profile():
    """
    Update the current user's profile.
    
    Regular users can only update: email, username.
    Admin users can additionally update: account_type, credits, referral_code, verified_status.
    """
    data = request.get_json()

    if not data or not isinstance(data, dict):
        return jsonify({'error': 'Invalid request body. JSON object required.'}), 400

    # Determine which fields the current user is allowed to modify
    if is_admin(current_user):
        allowed_fields = ALL_VALID_FIELDS
    else:
        allowed_fields = USER_EDITABLE_FIELDS

    # Separate requested fields into allowed and rejected
    requested_fields = set(data.keys())
    disallowed_fields = requested_fields - allowed_fields
    valid_fields = requested_fields & allowed_fields

    if disallowed_fields:
        return jsonify({
            'error': 'You do not have permission to modify the following fields.',
            'disallowed_fields': sorted(list(disallowed_fields)),
            'allowed_fields': sorted(list(allowed_fields))
        }), 403

    if not valid_fields:
        return jsonify({
            'error': 'No valid fields provided for update.',
            'allowed_fields': sorted(list(allowed_fields))
        }), 400

    # Validate field values before applying
    errors = {}

    if 'email' in valid_fields:
        email = data['email']
        if not isinstance(email, str) or '@' not in email or len(email) > 255:
            errors['email'] = 'A valid email address is required.'

    if 'username' in valid_fields:
        username = data['username']
        if not isinstance(username, str) or len(username) < 3 or len(username) > 64:
            errors['username'] = 'Username must be between 3 and 64 characters.'
        elif not username.isalnum() and not all(c.isalnum() or c in ('_', '-') for c in username):
            errors['username'] = 'Username may only contain alphanumeric characters, underscores, and hyphens.'

    if 'account_type' in valid_fields:
        account_type = data['account_type']
        valid_account_types = {'free', 'basic', 'premium', 'enterprise'}
        if account_type not in valid_account_types:
            errors['account_type'] = f'account_type must be one of: {sorted(valid_account_types)}'

    if 'credits' in valid_fields:
        credits_val = data['credits']
        if not isinstance(credits_val, (int, float)) or credits_val < 0:
            errors['credits'] = 'Credits must be a non-negative number.'

    if 'verified_status' in valid_fields:
        verified = data['verified_status']
        if not isinstance(verified, bool):
            errors['verified_status'] = 'verified_status must be a boolean.'

    if 'referral_code' in valid_fields:
        referral_code = data['referral_code']
        if not isinstance(referral_code, str) or len(referral_code) > 32:
            errors['referral_code'] = 'referral_code must be a string of at most 32 characters.'

    if errors:
        return jsonify({'error': 'Validation failed.', 'details': errors}), 422

    # Apply updates only for validated, allowed fields
    updated_fields = {}
    for field in valid_fields:
        value = data[field]
        setattr(current_user, field, value)
        updated_fields[field] = value

    # Persist changes (assumes a db session is available)
    try:
        from extensions import db
        db.session.commit()
    except ImportError:
        # Fallback if db module not configured yet (MVP)
        pass
    except Exception as e:
        try:
            from extensions import db
            db.session.rollback()
        except ImportError:
            pass
        return jsonify({'error': 'Failed to save profile updates.'}), 500

    return jsonify({
        'message': 'Profile updated successfully.',
        'updated_fields': updated_fields
    }), 200


